import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  describe("empty and trivial input", () => {
    it("returns [] for []", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged in value", () => {
      expect(mergeIntervals([[1, 3]])).toEqual([[1, 3]]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges the documented example [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("keeps the larger end when the second interval is shorter", () => {
      expect(mergeIntervals([[1, 10], [3, 6]])).toEqual([[1, 10]]);
    });

    it("merges a fully nested interval into the enclosing one", () => {
      expect(mergeIntervals([[1, 10], [2, 5]])).toEqual([[1, 10]]);
    });

    it("chains merges across several overlapping intervals", () => {
      expect(mergeIntervals([[1, 4], [3, 6], [5, 8]])).toEqual([[1, 8]]);
    });

    it("merges intervals sharing a start point, keeping the max end", () => {
      expect(mergeIntervals([[1, 3], [1, 5]])).toEqual([[1, 5]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges the documented example [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges degenerate point intervals that share an endpoint", () => {
      expect(mergeIntervals([[5, 5], [5, 5]])).toEqual([[5, 5]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps two non-overlapping intervals apart", () => {
      expect(mergeIntervals([[1, 2], [5, 6]])).toEqual([[1, 2], [5, 6]]);
    });

    it("does not merge intervals separated by a gap of one", () => {
      // [1,2] and [3,4] do not touch: 2 < 3, so they stay separate.
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("handles a mix of merged and separate groups", () => {
      expect(mergeIntervals([[1, 3], [2, 4], [8, 10], [15, 18], [16, 17]])).toEqual([
        [1, 4],
        [8, 10],
        [15, 18],
      ]);
    });
  });

  describe("result is sorted by start ascending", () => {
    it("sorts unsorted disjoint input", () => {
      expect(mergeIntervals([[5, 6], [1, 2], [3, 4]])).toEqual([
        [1, 2],
        [3, 4],
        [5, 6],
      ]);
    });

    it("sorts before merging overlapping input given out of order", () => {
      expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
    });
  });

  describe("negative and zero coordinates", () => {
    it("merges overlapping intervals spanning negatives and zero", () => {
      expect(mergeIntervals([[-5, -1], [-3, 0]])).toEqual([[-5, 0]]);
    });

    it("keeps disjoint negative intervals separate and sorted", () => {
      expect(mergeIntervals([[-1, 0], [-10, -5]])).toEqual([
        [-10, -5],
        [-1, 0],
      ]);
    });
  });

  describe("throws RangeError when start > end", () => {
    it("throws for a single invalid interval", () => {
      expect(() => mergeIntervals([[3, 1]])).toThrow(RangeError);
    });

    it("includes the offending interval in the message", () => {
      expect(() => mergeIntervals([[3, 1]])).toThrow("invalid interval [3, 1]");
    });

    it("throws even when a valid interval precedes the invalid one", () => {
      expect(() => mergeIntervals([[1, 2], [7, 4]])).toThrow(RangeError);
    });

    it("does not throw for a valid interval where start === end", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });
  });

  describe("input array and its pairs are never mutated", () => {
    it("leaves the outer array and inner pairs unchanged", () => {
      const input = [[3, 6], [1, 4], [8, 10]];
      mergeIntervals(input);
      expect(input).toEqual([[3, 6], [1, 4], [8, 10]]);
    });

    it("does not reorder the input array in place", () => {
      const input = [[5, 6], [1, 2]];
      const first = input[0];
      mergeIntervals(input);
      expect(input[0]).toBe(first);
    });

    it("returns a new array distinct from the input", () => {
      const input = [[1, 2]];
      const result = mergeIntervals(input);
      expect(result).not.toBe(input);
    });

    it("returns freshly allocated pairs, not references into the input", () => {
      const input = [[1, 2]];
      const result = mergeIntervals(input);
      expect(result[0]).not.toBe(input[0]);
    });
  });
});

